source_format:
{
  "templateId": "db-commissioning-report",
  "templateVersion": 1,
  "title": "DB Commissioning Report",
  "wizardSteps": [
    {
      "key": "header",
      "title": "Header",
      "sections": [
        "hdr"
      ]
    },
    {
      "key": "ir_test",
      "title": "IR Test",
      "sections": [
        "ir_test"
      ]
    },
    {
      "key": "check_list",
      "title": "Check List",
      "sections": [
        "procedure",
        "chk"
      ]
    },
    {
      "key": "signatures",
      "title": "Signatures",
      "sections": [
        "sigs"
      ]
    },
    {
      "key": "review",
      "title": "Review",
      "sections": []
    }
  ],
  "sections": [
    {
      "id": "hdr",
      "type": "header",
      "title": "COMMISSIONING REPORT - DB TESTING",
      "fields": [
        {
          "key": "vendor",
          "label": "VENDOR",
          "type": "text",
          "default": "Nirmaan (Stratos Infra Technologies Pvt. Ltd.)",
          "readonly": true
        },
        {
          "key": "project",
          "label": "PROJECT",
          "type": "text",
          "bind": "project.project_name",
          "readonly": true
        },
        {
          "key": "location",
          "label": "LOCATION",
          "type": "text",
          "bind": "project.location.full",
          "readonly": true
        },
        {
          "key": "date",
          "label": "DATE",
          "type": "date",
          "required": true
        },
        {
          "key": "db_name",
          "label": "DB NAME",
          "type": "text",
          "required": true,
          "placeholder": "e.g. DB-1A"
        }
      ]
    },
    {
      "id": "ir_test",
      "type": "measurement_matrix",
      "title": "1. IR Test:",
      "rows": [
        {
          "id": "r",
          "labels": {
            "pp": "R-Y",
            "pn": "R-N",
            "pe": "R-E"
          }
        },
        {
          "id": "y",
          "labels": {
            "pp": "Y-B",
            "pn": "Y-N",
            "pe": "Y-E"
          }
        },
        {
          "id": "b",
          "labels": {
            "pp": "B-Y",
            "pn": "B-N",
            "pe": "B-E"
          }
        }
      ],
      "columns": [
        {
          "key": "pp",
          "label": "Phase to Phase",
          "valueLabel": "In Volts",
          "type": "number",
          "unit": "V",
          "required": true,
          "min": 0
        },
        {
          "key": "pn",
          "label": "Phase to Neutral",
          "valueLabel": "In Volts",
          "type": "number",
          "unit": "V",
          "required": true,
          "min": 0
        },
        {
          "key": "pe",
          "label": "Phase to Earth",
          "valueLabel": "In Volts",
          "type": "number",
          "unit": "V",
          "required": true,
          "min": 0
        }
      ]
    },
    {
      "id": "procedure",
      "type": "fields",
      "title": "2. Check List",
      "layout": "stack",
      "fields": [
        {
          "key": "procedure_notes",
          "label": "PROCEDURE",
          "type": "textarea",
          "rows": 3,
          "default": "Remove lock out and tag out. Ensure no tools are left within the DB Panel. The main feeder is switched ON and the MCB line resistance parameter is noted using Multi-meter."
        }
      ]
    },
    {
      "id": "chk",
      "type": "checklist",
      "columns": [
        {
          "key": "slno",
          "label": "Sl No"
        },
        {
          "key": "particular",
          "label": "Particulars"
        },
        {
          "key": "result",
          "label": "Result"
        },
        {
          "key": "remarks",
          "label": "Remarks"
        }
      ],
      "items": [
        {
          "id": "q1",
          "particular": "All MCB off indication checked",
          "result": {
            "type": "select",
            "options": [
              "Okay",
              "Not Okay",
              "N/A"
            ],
            "default": "Okay"
          },
          "remarks": {
            "type": "text"
          }
        },
        {
          "id": "q2",
          "particular": "All MCB ON indication checked",
          "result": {
            "type": "select",
            "options": [
              "Okay",
              "Not Okay",
              "N/A"
            ],
            "default": "Okay"
          },
          "remarks": {
            "type": "text"
          }
        },
        {
          "id": "q3",
          "particular": "All MCB TRIP indication checked",
          "result": {
            "type": "select",
            "options": [
              "Okay",
              "Not Okay",
              "N/A"
            ],
            "default": "Okay"
          },
          "remarks": {
            "type": "text"
          }
        },
        {
          "id": "q4",
          "particular": "All MCB ON/OFF Function checked",
          "result": {
            "type": "select",
            "options": [
              "Okay",
              "Not Okay",
              "N/A"
            ],
            "default": "Okay"
          },
          "remarks": {
            "type": "text"
          }
        }
      ]
    },
    {
      "id": "sigs",
      "type": "signatures",
      "blocks": [
        {
          "key": "tested_by",
          "label": "TESTED BY"
        },
        {
          "key": "hvac_consultant",
          "label": "HVAC CONSULTANT"
        },
        {
          "key": "client",
          "label": "CLIENT"
        }
      ]
    }
  ]
}

{
  "templateId": "socket-testing-report",
  "templateVersion": 1,
  "title": "Socket Testing Report",
  "wizardSteps": [
    {
      "key": "header",
      "title": "Header",
      "sections": [
        "hdr"
      ]
    },
    {
      "key": "sockets",
      "title": "Sockets",
      "sections": [
        "sockets"
      ]
    },
    {
      "key": "signatures",
      "title": "Signatures",
      "sections": [
        "sigs"
      ]
    },
    {
      "key": "review",
      "title": "Review",
      "sections": []
    }
  ],
  "sections": [
    {
      "id": "hdr",
      "type": "header",
      "title": "COMMISSIONING REPORT - SOCKET TESTING",
      "fields": [
        {
          "key": "vendor",
          "label": "VENDOR",
          "type": "text",
          "default": "Nirmaan (Stratos Infra Technologies Pvt. Ltd.)",
          "readonly": true
        },
        {
          "key": "project",
          "label": "PROJECT",
          "type": "text",
          "bind": "project.project_name",
