        },
        {
          "key": "date",
          "label": "DATE",
          "type": "date",
          "required": true
        }
      ]
    },
    {
      "id": "sockets",
      "type": "trainees_data_table",
      "title": "Socket Testing",
      "minRows": 1,
      "maxRows": 100,
      "addRowLabel": "Add another socket",
      "columns": [
        {
          "key": "circuit_no",
          "label": "Circuit No.",
          "type": "text",
          "required": true,
          "width": "20%"
        },
        {
          "key": "area",
          "label": "Area",
          "type": "text",
          "required": true,
          "width": "45%"
        },
        {
          "key": "output_voltage",
          "label": "Output Voltage",
          "type": "number",
          "unit": "V",
          "required": true,
          "min": 0,
          "width": "25%"
        }
      ]
    },
    {
      "id": "sigs",
      "type": "signatures",
      "blocks": [
        {
          "key": "tested_by",
          "label": "TESTED BY"
        },
        {
          "key": "hvac_consultant",
          "label": "HVAC CONSULTANT"
        },
        {
          "key": "client",
          "label": "CLIENT"
        }
      ]
    }
  ]
}

{
  "templateId": "nitrogen-pressure-testing-report",
  "templateVersion": 1,
  "title": "Nitrogen Pressure Testing Report",
  "wizardSteps": [
    {
      "key": "header",
      "title": "Header",
      "sections": [
        "hdr"
      ]
    },
    {
      "key": "testing_report",
      "title": "Testing Report",
      "sections": [
        "chk"
      ]
    },
    {
      "key": "details",
      "title": "Test Details",
      "sections": [
        "details",
        "evidence"
      ]
    },
    {
      "key": "signatures",
      "title": "Signatures",
      "sections": [
        "sigs"
      ]
    },
    {
      "key": "review",
      "title": "Review",
      "sections": []
    }
  ],
  "sections": [
    {
      "id": "hdr",
      "type": "header",
      "title": "REFRIGERANT LINE PRESSURE TESTING REPORT",
      "fields": [
        {
          "key": "vendor",
          "label": "VENDOR",
          "type": "text",
          "default": "Nirmaan (Stratos Infra Technologies Pvt. Ltd.)",
          "readonly": true
        },
        {
          "key": "project",
          "label": "PROJECT",
          "type": "text",
          "bind": "project.project_name",
          "readonly": true
        },
        {
          "key": "location",
          "label": "LOCATION",
          "type": "text",
          "bind": "project.location.full",
          "readonly": true
        },
        {
          "key": "package",
          "label": "PACKAGE",
          "type": "text",
          "required": true,
          "placeholder": "e.g. HVAC"
        },
        {
          "key": "rating",
          "label": "Rating (in HP)",
          "type": "number",
          "unit": "HP",
          "required": true,
          "min": 0
        },
        {
          "key": "area",
          "label": "AREA",
          "type": "text",
          "required": true
        }
      ]
    },
    {
      "id": "chk",
      "type": "checklist",
      "title": "Testing Report",
      "columns": [
        {
          "key": "slno",
          "label": "Sl No"
        },
        {
          "key": "particular",
          "label": "Particulars"
        },
        {
          "key": "result",
          "label": "Results"
        },
        {
          "key": "remarks",
          "label": "Remarks"
        }
      ],
      "items": [
        {
          "id": "q1",
          "particular": "The system maintained the specified pressure levels throughout the testing duration.",
          "result": {
            "type": "select",
            "options": [
              "Yes",
              "No",
              "N/A"
            ],
            "default": "Yes"
          },
          "remarks": {
            "type": "text"
          }
        },
        {
          "id": "q2",
          "particular": "No visible leaks were detected during the visual inspection.",
          "result": {
            "type": "select",
            "options": [
              "Yes",
              "No",
              "N/A"
            ],
            "default": "Yes"
          },
          "remarks": {
            "type": "text"
          }
        },
        {
          "id": "q3",
          "particular": "Electronic leak detection tools confirmed the absence of leaks.",
          "result": {
            "type": "select",
            "options": [
              "Yes",
              "No",
              "N/A"
            ],
            "default": "Yes"
          },
          "remarks": {
            "type": "text"
          }
        },
        {
          "id": "q4",
          "particular": "The above all are working fine",
          "result": {
            "type": "select",
            "options": [
              "Yes",
              "No",
              "N/A"
            ],
            "default": "Yes"
          },
          "remarks": {
            "type": "text"
          }
        }
      ]
    },
    {
      "id": "details",
      "type": "fields",
      "title": "Test Details",
      "layout": "grid",
      "columns": 2,
      "fields": [
        {
          "key": "test_start_date",
          "label": "Test Start Date",
          "type": "date",
          "required": true
        },
        {
          "key": "test_end_date",
          "label": "Test End Date",
          "type": "date",
          "required": true
        },
        {
          "key": "measured_pressure",
          "label": "The measured pressure rating is",
          "type": "number",
          "unit": "PSI",
          "required": true,
          "min": 0
        }
      ]
    },
    {
      "id": "evidence",
      "type": "image_attachments",
      "title": "Test Photos / Evidence",
      "columns": 2,
      "slots": [
        {
          "key": "test_photo_1",
          "label": "Test Photo 1",
          "multi": false,
          "accept": "image/*",
          "maxSizeMb": 5,
          "required": false
        },
        {
          "key": "test_photo_2",
          "label": "Test Photo 2",
          "multi": false,
          "accept": "image/*",
          "maxSizeMb": 5,
          "required": false
        }
      ]
    },
    {
      "id": "sigs",
      "type": "signatures",
      "blocks": [
        {
          "key": "tested_by",
          "label": "TESTED BY"
        },
        {
          "key": "hvac_consultant",
          "label": "HVAC CONSULTANT"
        },
        {
          "key": "client",
          "label": "CLIENT"
        }
      ]
    }
  ]
}

{
  "templateId": "vrf-dx-commissioning-report",
  "templateVersion": 1,
  "title": "VRF / DX Commissioning Report",
  "wizardSteps": [
    {
      "key": "header",
      "title": "Header",
      "sections": [
        "hdr",
        "unit_choice"
      ]
    },
    {
      "key": "vrf_tests",
      "title": "VRF Tests",
      "sections": [
        "vrf_physical",
        "vrf_timer"
      ],
      "visibleIf": {
        "field": "responses.unit_choice.unit_type",
        "in": [
          "VRF",
          "Both"
        ]
      }
    },
    {
      "key": "dx_tests",
      "title": "DX Tests",
      "sections": [
        "dx_physical",
        "dx_timer"
      ],
      "visibleIf": {
        "field": "responses.unit_choice.unit_type",
        "in": [
          "DX",
          "Both"
        ]
      }
    },
    {
      "key": "signatures",
      "title": "Signatures",
      "sections": [
        "sigs"
      ]
    },
    {
      "key": "review",
      "title": "Review",
      "sections": []
    }
  ],
  "sections": [
    {
      "id": "hdr",
      "type": "header",
      "title": "COMMISSIONING REPORT - VRF / DX UNIT",
      "fields": [
        {
          "key": "vendor",
          "label": "VENDOR",
          "type": "text",
          "default": "Nirmaan (Stratos Infra Technologies Pvt. Ltd.)",
          "readonly": true
        },
        {
          "key": "project",
          "label": "PROJECT",
          "type": "text",
          "bind": "project.project_name",
          "readonly": true
        },
        {
          "key": "location",
          "label": "LOCATION",
          "type": "text",
          "bind": "project.location.full",
          "readonly": true
        },
        {
          "key": "package",
          "label": "PACKAGE",
          "type": "text",
          "required": true,
          "placeholder": "e.g. HVAC"
        },
        {
          "key": "equipment",
          "label": "EQUIPMENT",
          "type": "text",
          "required": true
        },
        {
          "key": "area",
          "label": "AREA",
          "type": "text",
          "required": true
        }
      ]
    },
    {
      "id": "unit_choice",
      "type": "fields",
      "title": "Unit Selection",
      "layout": "stack",
      "fields": [
        {
          "key": "unit_type",
          "label": "Do you go with VRF, DX, or Both?",
          "type": "select",
          "options": [
            "VRF",
            "DX",
            "Both"
          ],
          "required": true,
          "default": "DX",
          "helpText": "Determines which unit's checklists print on the PDF. Wizard shows all four checklists — fill only the ones relevant to your selection."
        }
      ]
    },
    {
      "id": "vrf_physical",
      "type": "checklist",
      "title": "Physical Test",
      "columns": [
        {
          "key": "slno",
          "label": "Sl No"
        },
        {
          "key": "particular",
          "label": "Particulars"
        },
        {
          "key": "result",
          "label": "Results"
        },
        {
          "key": "remarks",
          "label": "Remarks"
        }
      ],
      "items": [
        {
          "id": "v1",
          "particular": "Visual inspection General state",
          "result": {
            "type": "select",
            "options": [
              "Yes",
              "No",
              "OK",
              "Not OK",
              "NA"
            ],
            "default": "Yes"
          },
          "remarks": {
            "type": "text"
          }
        },
        {
          "id": "v2",
          "particular": "Any refrigerant leakage?",
          "result": {
            "type": "select",
            "options": [
              "Yes",
              "No",
              "OK",
              "Not OK",
              "NA"
            ],
            "default": "No"
          },
          "remarks": {
            "type": "text"
          }
        },
        {
          "id": "v3",
          "particular": "Both stop valves open before the operation",
          "result": {
            "type": "select",
            "options": [
              "Yes",
              "No",
              "OK",
              "Not OK",
              "NA"
            ],
            "default": "Yes"
          },
          "remarks": {
            "type": "text"
          }
        },
        {
          "id": "v4",
          "particular": "Position of sensors (Ok or Not Ok)",
          "result": {
            "type": "select",
            "options": [
              "Yes",
              "No",
              "OK",
              "Not OK",
              "NA"
            ],
            "default": "OK"
          },
          "remarks": {
            "type": "text"
          }
        },
        {
          "id": "v5",
          "particular": "Corrosion/oxidation (Ok or Not Ok)",
          "result": {
            "type": "select",
            "options": [
              "Yes",
              "No",
              "OK",
              "Not OK",
              "NA"
            ],
            "default": "OK"
          },
          "remarks": {
            "type": "text"
          }
        },
        {
          "id": "v6",
          "particular": "Vibrations/frictions in the machine",
          "result": {
            "type": "select",
            "options": [
              "Yes",
              "No",
              "OK",
              "Not OK",
              "NA"
            ],
            "default": "No"
          },
          "remarks": {
            "type": "text"
          }
        },
        {
          "id": "v7",
          "particular": "Any unusual Noise in the machine?",
          "result": {
            "type": "select",
            "options": [
              "Yes",
              "No",
              "OK",
              "Not OK",
              "NA"
            ],
            "default": "No"
          },
          "remarks": {
            "type": "text"
          }
        },
        {
          "id": "v8",
          "particular": "Piping length within acceptable limits",
          "result": {
            "type": "select",
            "options": [
              "Yes",
              "No",
              "OK",
              "Not OK",
              "NA"
            ],
            "default": "Yes"
          },
          "remarks": {
            "type": "text"
          }
        },
        {
          "id": "v9",
          "particular": "Thermostat operation and settings.",
          "result": {
            "type": "select",
            "options": [
              "Yes",
              "No",
              "OK",
              "Not OK",
              "NA"
            ],
            "default": "NA"
          },
          "remarks": {
            "type": "text"
          }
        },
        {
          "id": "v10",
          "particular": "Drainage bottom plate (Ok or Not Ok)",
          "result": {
            "type": "select",
            "options": [
              "Yes",
              "No",
              "OK",
              "Not OK",
              "NA"
            ],
            "default": "OK"
          },
          "remarks": {
            "type": "text"
          }
        },
        {
          "id": "v11",
          "particular": "Refrigerant Piping is properly insulated.",
          "result": {
            "type": "select",
            "options": [
              "Yes",
              "No",
              "OK",
              "Not OK",
              "NA"
            ],
            "default": "Yes"
          },
          "remarks": {
            "type": "text"
          }
        },
        {
          "id": "v12",
          "particular": "The voltage and Current record within acceptable limits",
          "result": {
            "type": "select",
            "options": [
              "Yes",
              "No",
              "OK",
              "Not OK",
              "NA"
            ],
            "default": "Yes"
          },
          "remarks": {
            "type": "text"
          }
        },
        {
          "id": "v13",
          "particular": "All the safety devices are functional.",
          "result": {
            "type": "select",
            "options": [
              "Yes",
              "No",
              "OK",
              "Not OK",
              "NA"
            ],
            "default": "Yes"
          },
          "remarks": {
            "type": "text"
          }
        },
        {
          "id": "v14",
          "particular": "Cable Section as per standards.",
          "result": {
            "type": "select",
            "options": [
              "Yes",
              "No",
              "OK",
              "Not OK",
              "NA"
            ],
            "default": "Yes"
          },
          "remarks": {
            "type": "text"
          }
        }
      ]
    },
    {
      "id": "vrf_timer",
      "type": "process",
      "title": "Functionality Test of Timer",
      "blocks": [
        {
          "subtitle": "",
          "items": [
            "VRF unit is getting switched ON or OFF automatically When Placed in Auto Test Mode."
          ]
        }
      ]
    },
    {
      "id": "dx_physical",
      "type": "checklist",
      "title": "Physical Test",
      "columns": [
        {
          "key": "slno",
          "label": "Sl No"
        },
        {
          "key": "particular",
          "label": "Particulars"
        },
        {
          "key": "result",
          "label": "Results"
        },
        {
          "key": "remarks",
          "label": "Remarks"
        }
      ],
      "items": [
        {
          "id": "d1",
          "particular": "Visual inspection General state",
          "result": {
            "type": "select",
            "options": [
              "Yes",
              "No",
              "OK",
              "Not OK",
              "NA"
            ],
            "default": "Yes"
          },
          "remarks": {
            "type": "text"
          }
        },
        {
          "id": "d2",
          "particular": "Any refrigerant leakage?",
          "result": {
            "type": "select",
            "options": [
              "Yes",
              "No",
              "OK",
              "Not OK",
